class Solution:
  def minCoins(self, coins, n, amount):
    dp = [float('inf')] * (amount + 1)
    dp[0] = 0
    for i in range(amount + 1):
      for j in range(n):
        if coins[j] <= i:
          dp[i] = min(dp[i], dp[i - coins[j]] + 1)
    return dp[amount] if dp[amount] != float('inf') else -1

